// shimFixture creates a minimal Shim for emit tests.
func shimFixture() *shimgen.Shim {
	surface := staticSurface()
	return shimgen.Synth("TestLib", "1.0.0", "net8.0", surface)
}

func TestEmitBridgeCSHeader(t *testing.T) {
	s := shimFixture()
	out := shimgen.EmitBridgeCS(s)
	for _, want := range []string{
		"// Bridge.cs -- generated by github.com/mochilang/mochi-dotnet/shimgen; do not edit.",
		"// upstream package: TestLib 1.0.0",
	} {
		if !strings.Contains(out, want) {
			t.Errorf("Bridge.cs missing %q\nfull output:\n%s", want, out)
		}
	}
}

func TestEmitBridgeCSUsings(t *testing.T) {
	s := shimFixture()
	out := shimgen.EmitBridgeCS(s)
	for _, want := range []string{
		"using System;",
		"using System.Runtime.InteropServices;",
		"using System.Text;",
	} {
		if !strings.Contains(out, want) {
			t.Errorf("Bridge.cs missing using %q", want)
		}
	}
}

