func TestEmitBridgeCSMarshalFree(t *testing.T) {
	s := shimFixture()
	out := shimgen.EmitBridgeCS(s)
	if !strings.Contains(out, `[UnmanagedCallersOnly(EntryPoint = "mochi_marshal_free")]`) {
		t.Errorf("Bridge.cs missing MarshalFree attribute\nfull:\n%s", out)
	}
	if !strings.Contains(out, "public static void MarshalFree(nint ptr)") {
		t.Errorf("Bridge.cs missing MarshalFree method\nfull:\n%s", out)
	}
}

func TestEmitBridgeCSUnmanagedCallersOnly(t *testing.T) {
	s := shimFixture()
	out := shimgen.EmitBridgeCS(s)
	for _, m := range s.Methods {
		want := `[UnmanagedCallersOnly(EntryPoint = "` + m.EntryPoint + `")]`
		if !strings.Contains(out, want) {
			t.Errorf("Bridge.cs missing attribute for %s:\n  want: %s\nfull:\n%s",
				m.EntryPoint, want, out)
		}
	}
}

