func TestEmitBridgeCSNamespaceDotted(t *testing.T) {
	surface := &metacli.ApiSurface{
		Types: []metacli.SurfaceType{},
	}
	s := shimgen.Synth("Newtonsoft.Json", "13.0.3", "net8.0", surface)
	out := shimgen.EmitBridgeCS(s)
	// Dots should be removed from namespace.
	if strings.Contains(out, "namespace MochiShim.Newtonsoft.Json") {
		t.Errorf("Bridge.cs namespace should not have dots from package name")
	}
	if !strings.Contains(out, "namespace MochiShim.NewtonsoftJson") {
		t.Errorf("Bridge.cs missing MochiShim.NewtonsoftJson namespace\nfull:\n%s", out)
	}
}

func TestEmitBridgeCSStringReturn(t *testing.T) {
	surface := &metacli.ApiSurface{
		Types: []metacli.SurfaceType{
			{
				FullName:  "Demo.Util",
				ShortName: "Util",
				Namespace: "Demo",
				Kind:      metacli.KindClass,
				IsStatic:  true,
				Methods: []metacli.SurfaceMethod{
					{
						Name:     "Greet",
						IsStatic: true,
						ReturnType: metacli.TypeRef{
							FullName: "System.String",
							Kind:     metacli.TypeRefPrimitive,
						},
						Params: []metacli.ParamDef{
							{Name: "name", Type: metacli.TypeRef{FullName: "System.String", Kind: metacli.TypeRefPrimitive}},
						},
					},
				},
			},
		},
	}
	s := shimgen.Synth("Demo", "1.0.0", "net8.0", surface)
	out := shimgen.EmitBridgeCS(s)
	// String return should produce MochiString return type.
	if !strings.Contains(out, "MochiString") {
		t.Errorf("string return method should use MochiString type\nfull:\n%s", out)
	}
	if !strings.Contains(out, "MochiStringFromManaged") {
		t.Errorf("string return method should call MochiStringFromManaged\nfull:\n%s", out)
	}
}

