func TestEmitSkippedTXTEmpty(t *testing.T) {
	s := &shimgen.Shim{}
	out := shimgen.EmitSkippedTXT(s)
	if out != "# No skipped items.\n" {
		t.Errorf("empty SKIPPED.txt = %q; want '# No skipped items.'", out)
	}
}

func TestEmitSkippedTXTFormat(t *testing.T) {
	s := shimFixture()
	out := shimgen.EmitSkippedTXT(s)
	// Should have at least one group since UnsafeOp is skipped.
	if !strings.Contains(out, "# SkipPointer") {
		t.Errorf("SKIPPED.txt missing # SkipPointer group\nfull:\n%s", out)
	}
	if !strings.Contains(out, "SKIPPED: ") {
		t.Errorf("SKIPPED.txt missing SKIPPED: lines\nfull:\n%s", out)
	}
	if !strings.Contains(out, "Reason: SkipPointer") {
		t.Errorf("SKIPPED.txt missing Reason: SkipPointer\nfull:\n%s", out)
	}
}

func TestEmitDeterministic(t *testing.T) {
	s := shimFixture()
	first := shimgen.EmitBridgeCS(s)
	for range 5 {
		got := shimgen.EmitBridgeCS(s)
		if got != first {
			t.Error("EmitBridgeCS non-deterministic")
		}
	}
}

func TestEmitCsprojDeterministic(t *testing.T) {
	s := shimFixture()
	first := shimgen.EmitCsproj(s)
	for range 5 {
		if shimgen.EmitCsproj(s) != first {
			t.Error("EmitCsproj non-deterministic")
		}
	}
}
